INSERT INTO `health_packages` VALUES (6,'Gói khám Tổng quát Cơ bản','Khám sức khỏe tổng quát định kỳ cho cá nhân, bao gồm các xét nghiệm cơ bản, siêu âm và tư vấn bác sĩ.',900000.00,'health-packages/1657a734-39ac-4622-abee-b0c7885186b1.webp','2026-04-22 18:22:16','[]','ACTIVE'),(7,'Gói khám Tổng quát Nâng cao','Gói khám toàn diện bao gồm đầy đủ các xét nghiệm, chẩn đoán hình ảnh chuyên sâu và đánh giá chức năng các cơ quan.',1800000.00,'health-packages/a88b6600-e773-48a0-8ae2-d961b4ad6986.webp','2026-04-22 18:22:16','[]','ACTIVE'),(8,'Gói tầm soát Ung thư Phụ nữ','Tầm soát chuyên sâu các bệnh lý ung thư phổ biến ở nữ giới như ung thư vú, cổ tử cung, buồng trứng.',2500000.00,'health-packages/7c6032f1-b4c7-4b51-b1e2-88ca6a2e3631.webp','2026-04-22 18:22:16','[]','ACTIVE'),(9,'Gói tầm soát Ung thư Nam giới','Tầm soát các bệnh lý ung thư thường gặp ở nam giới như ung thư gan, phổi, đại trực tràng, tuyến tiền liệt.',2200000.00,'health-packages/8a39d9ec-2b4c-446d-9586-9014c3ea487c.webp','2026-04-22 18:22:16','[]','ACTIVE'),(10,'Gói khám Sức khỏe Tiền hôn nhân','Kiểm tra sức khỏe tổng quát và sức khỏe sinh sản cho các cặp đôi trước khi kết hôn.',1500000.00,'health-packages/9e6ba98b-92a0-46d0-a013-09667aea22d0.webp','2026-04-22 18:22:16','[]','ACTIVE'),(11,'Gói tầm soát Tim mạch chuyên sâu','Đánh giá nguy cơ tim mạch, bao gồm điện tâm đồ, siêu âm tim và các xét nghiệm mỡ máu.',1200000.00,'health-packages/db5656af-7a0d-46ac-8ee4-9b9392607e2a.webp','2026-04-22 18:22:16','[]','ACTIVE'),(12,'Gói khám Nhi khoa định kỳ','Kiểm tra sức khỏe, sự phát triển và tư vấn dinh dưỡng, tiêm chủng cho trẻ em.',500000.00,'health-packages/d411e228-30ea-48d3-abc4-ab88615d1016.webp','2026-04-22 18:22:16','[]','ACTIVE'),(13,'Gói tầm soát Dạ dày & Đại tràng','Tầm soát các bệnh lý tiêu hóa, phát hiện sớm polyp và ung thư đường tiêu hóa.',3000000.00,'health-packages/8f124ea2-06cc-4cc7-9d5a-b9bd85bb213e.webp','2026-04-22 18:22:16','[]','ACTIVE'),(14,'Gói khám Răng - Hàm - Mặt','Kiểm tra sức khỏe răng miệng tổng quát, lấy cao răng và tư vấn thẩm mỹ nha khoa.',700000.00,'https://img.freepik.com/free-photo/dentist-working-patient_23-2148825232.jpg','2026-04-22 18:22:16','[]','INACTIVE'),(15,'Gói chăm sóc Da liễu Nâng cao','Khám và tư vấn các bệnh lý về da, tầm soát ung thư da và tư vấn liệu trình chăm sóc da chuyên sâu.',1000000.00,'https://img.freepik.com/free-photo/dermatologist-examining-patient-skin_23-2148816223.jpg','2026-04-22 18:22:16','[]','INACTIVE'),(16,'XÉT NGHIỆM MÁU','XN',200000.00,'health-packages/1369c132-d463-4b5c-b198-286491c7e192.webp','2026-05-16 12:14:05','[]','ACTIVE');
/*!40000 ALTER TABLE `health_packages` ENABLE KEYS */;
